{
  "learning_outcomes": [
    {
      "unit_name": "Unit–I Electrostatics",
      "chapter_name": "Electric Charges and Fields",
      "topic": "Electric Charges and Fields Competencies",
      "outcomes": [
        "Apply superposition principle to calculate net force on charges in a system."
      ]
    },
    {
      "unit_name": "Unit–I Electrostatics",
      "chapter_name": "Electrostatic Potential and Capacitance",
      "topic": "Electrostatic Potential and Capacitance Competencies",
      "outcomes": [
        "Analyze series and parallel combinations of capacitors to determine equivalent capacitance."
      ]
    },
    {
      "unit_name": "Unit-II Current Electricity",
      "chapter_name": "Current Electricity",
      "topic": "Current Electricity Competencies",
      "outcomes": [
        "Utilize Kirchhoff's laws to solve complex electrical circuits."
      ]
    },
    {
      "unit_name": "Unit-III Magnetic Effects of Current and Magnetism",
      "chapter_name": "Moving Charges and Magnetism",
      "topic": "Moving Charges and Magnetism Competencies",
      "outcomes": [
        "Calculate force exerted by a uniform magnetic field on current-carrying conductors."
      ]
    },
    {
      "unit_name": "Unit-III Magnetic Effects of Current and Magnetism",
      "chapter_name": "Magnetism and Matter",
      "topic": "Magnetism and Matter Competencies",
      "outcomes": [
        "Differentiate between paramagnetic, diamagnetic, and ferromagnetic behaviors qualitatively."
      ]
    },
    {
      "unit_name": "Unit-IV Electromagnetic Induction and Alternating Currents",
      "chapter_name": "Electromagnetic Induction",
      "topic": "Electromagnetic Induction Competencies",
      "outcomes": [
        "Explain Faraday's Law of Electromagnetic Induction",
        "Apply Lenz's Law to determine direction of induced current",
        "Analyze self-inductance and mutual inductance phenomena"
      ]
    },
    {
      "unit_name": "Unit-IV Electromagnetic Induction and Alternating Currents",
      "chapter_name": "Alternating Current",
      "topic": "Alternating Current Competencies",
      "outcomes": [
        "Define and calculate RMS values for AC quantities",
        "Analyze behavior of LCR series resonance circuits",
        "Differentiate between peak, average, and RMS values"
      ]
    },
    {
      "unit_name": "Unit–V Electromagnetic Waves",
      "chapter_name": "Electromagnetic Waves",
      "topic": "Electromagnetic Waves Competencies",
      "outcomes": [
        "Describe the transverse nature of electromagnetic waves",
        "Explain the electromagnetic spectrum and its regions",
        "Relate electric and magnetic field oscillations in EM waves"
      ]
    },
    {
      "unit_name": "Unit–VI Optics",
      "chapter_name": "Ray Optics and Optical Instruments",
      "topic": "Ray Optics Competencies",
      "outcomes": [
        "Derive lens maker's formula for thin lenses",
        "Calculate magnification in microscopes and telescopes",
        "Analyze total internal reflection phenomena"
      ]
    },
    {
      "unit_name": "Unit–VI Optics",
      "chapter_name": "Wave Optics",
      "topic": "Wave Optics Competencies",
      "outcomes": [
        "Apply Huygens' principle to wave propagation",
        "Analyze Young's double-slit experiment results",
        "Explain conditions for constructive and destructive interference"
      ]
    },
    {
      "unit_name": "Unit–VII Dual Nature of Radiation and Matter",
      "chapter_name": "Dual Nature of Radiation and Matter",
      "topic": "Dual Nature of Radiation and Matter Competencies",
      "outcomes": [
        "Explain the experimental evidence for the particle nature of light through the photoelectric effect.",
        "Describe the concept of de Broglie wavelength associated with moving particles.",
        "Analyze the relationship between photon energy, work function, and stopping potential."
      ]
    },
    {
      "unit_name": "Unit-VIII Atoms and Nuclei",
      "chapter_name": "Atoms",
      "topic": "Atoms Competencies",
      "outcomes": [
        "Evaluate the limitations of Rutherford's model and explain Bohr's postulates for hydrogen atom stability.",
        "Derive expressions for orbital radii and energy levels in the hydrogen atom.",
        "Classify different spectral series (Lyman, Balmer, Paschen) based on electron transitions."
      ]
    },
    {
      "unit_name": "Unit-VIII Atoms and Nuclei",
      "chapter_name": "Nuclei",
      "topic": "Nuclei Competencies",
      "outcomes": [
        "Calculate mass defect and binding energy per nucleon to explain nuclear stability.",
        "Differentiate between nuclear fission and fusion mechanisms and their respective applications in energy production.",
        "Analyze the laws of radioactivity including decay constants and half-life calculations."
      ]
    },
    {
      "unit_name": "Unit–IX Electronic Devices",
      "chapter_name": "Materials, Devices and Simple Circuits",
      "topic": "Materials, Devices and Simple Circuits Competencies",
      "outcomes": [
        "Distinguish between intrinsic and extrinsic semiconductors based on doping types (n-type/p-type).",
        "Interpret the V-I characteristics of p-n junction diodes in forward and reverse bias conditions.",
        "Design simple circuits using transistors as amplifiers or switches and analyze logic gate combinations."
      ]
    }
  ]
}
